    stars: [
      { pos: [ 2.2,  1.4,  0.3] }, { pos: [ 3.0,  0.9, -0.2] },
      { pos: [ 1.6,  0.7,  0.5] }, { pos: [ 2.7,  2.0,  0.1] },
      { pos: [ 1.9,  2.1, -0.4] },
    ],
